#!/usr/bin/env node
/**
 * 
 * 配置方法
 * 变量名: XFHK1, XFHK2, XFHK3... (支持多个账号)
 * 变量值: accessKey#androidId#oaid#brand#model
 * 例如: a4d8d4a7...#eb68e9f0d...f#7cabc...#Xiaomi#22041216C
 * 
 * 其他环境变量（支持账号特定配置，使用前缀 最好使用默认配置）：
 * XFHK1_ECPM_MIN, XFHK1_ECPM_MAX, XFHK1_MAX_CLAIMS, XFHK1_DELAY_MIN, XFHK1_DELAY_MAX, XFHK1_MAX_WITHDRAWALS
 * XFHK1_VIDEO_TIMES, XFHK1_VIDEO_JG

 * （看自己需求）提现金币阈值: TXcoin1, TXcoin2, TXcoin3...（对应每个账号，默认5000）
 */

const crypto = require('crypto');
