const DEFAULTS = {
    // ecpm范围（用于任务领取和提现等操作 不要动！）
    ecpmMin: 500,
    ecpmMax: 1500,
    
    // 领取次数：每次运行最多领取几个任务（默认30次）
    maxClaims: 10,
    
    // 延迟时间：每次领取之间的延迟（秒），默认120-180秒随机
    delayRange: [120, 180],
    
    // ===== 提现配置 =====
    // 金币阈值：当金币大于此值时触发提现（默认5000）
    withdrawThreshold: 5000,
    
    // 最大提现次数：达到此次数后停止脚本（默认10次）
    maxWithdrawals: 10,
    
    // ===== 视频广告配置 =====
    // 视频广告执行次数（默认10次）
    videoTimes: 10,
    
    // 视频广告间隔（秒），默认60-120秒随机
    videoInterval: [20, 40]
};
